    /**
    * Calls:
    * 1 - (200) POST:/WebGoat/SqlInjectionAdvanced/attack6a
    * 2 - (200) POST:/WebGoat/JWT/jku/follow/{user}
    * 3 - (200) POST:/WebGoat/JWT/jku/follow/{user}
    * Found 1 potential fault of type-code 101
    */
    @Test(timeout = 60000)
    public void test_59_postOnFollowReturnsMismatchResponseWithSchema() throws Exception {
        
        final Map<String,String> cookies_user1 = given()
            .contentType("application/x-www-form-urlencoded")
            .body("username=testuser&password=testuser")
            .post(baseUrlOfSut + "/WebGoat/login")
            .then().extract().cookies();
            
        
        // Fault101. Received A Response From API With A Structure/Data That Is Not Matching Its Schema. Type: validation.response.body.schema.type [Path '/feedbackArgs'] Instance type (null) does not match any allowed primitive type (allowed: ["array"])
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .cookies(cookies_user1)
                .post(baseUrlOfSut + "/WebGoat/SqlInjectionAdvanced/attack6a?userid_6a=owsHrLpq")
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("application/json")
                .body("'lessonCompleted'", equalTo(false))
                .body("'feedback'", containsString("Sorry the solution is not correct, please try again."))
                .body("'feedbackArgs'", nullValue())
                .body("'output'", containsString("org.owasp.webgoat.lessons.sqlinjection.advanced.SqlInjectionLesson6a : Schema \\\"testuser\\\" not found; SQL statement:\\nSET SCHEMA \\\"testuser\\\" [90079-195]<br> Your query was: SELECT * FROM user_data WHERE last_name = 'owsHrLpq'"))
                .body("'outputArgs'", nullValue())
                .body("'assignment'", containsString("SqlInjectionLesson6a"))
                .body("'attemptWasMade'", equalTo(true));
        
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .cookies(cookies_user1)
                .post(baseUrlOfSut + "/WebGoat/JWT/jku/follow/R")
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("text/plain")
                .body(containsString("You are now following Tom"));
        
        given().accept("*/*")
                .header("x-EMextraHeader123", "")
                .cookies(cookies_user1)
                .post(baseUrlOfSut + "/WebGoat/JWT/jku/follow/R?" + 
                    "enabled.x=_EM_883_XYZ_&" + 
                    "enabled.y=hrN7_jjMHezc9YCL&" + 
                    "networkNum.x=H8Tuhji1cvn5Niyq&" + 
                    "network_num.x=_EM_885_XYZ_")
                .then()
                .statusCode(200)
                .assertThat()
                .contentType("text/plain")
                .body(containsString("You are now following Tom"));
    }
    
    
